const cloudflareAPIBase = "https://api.cloudflare.com/client/v4"

// apiBaseOverride allows tests to redirect API calls to a test server.
var apiBaseOverride = cloudflareAPIBase

// DeployResult holds the result of a deployment.
type DeployResult struct {
	URL       string
	Script    string
	AccountID string
}

// cfResponse is the common Cloudflare API response wrapper.
type cfResponse struct {
	Success bool `json:"success"`
	Errors  []struct {
		Code    int    `json:"code"`
		Message string `json:"message"`
	} `json:"errors"`
	Result json.RawMessage `json:"result"`
}

func (r *cfResponse) ErrorString() string {
	if len(r.Errors) == 0 {
		return "unknown error"
	}
	var parts []string
	for _, e := range r.Errors {
		parts = append(parts, fmt.Sprintf("[%d] %s", e.Code, e.Message))
	}
	return strings.Join(parts, "; ")
}

// GenerateScript returns the Worker JavaScript source.
// The JS reads all config from Cloudflare environment variables —
// no model mappings or upstream URL are embedded in the source.
// The source file is committed at worker.js in the repo root for
// direct GitHub access: https://raw.githubusercontent.com/zeevrussak/z-api-proxy/master/worker.js
func GenerateScript(cfg *config.Config) string {
	return workerScriptSource
}

// workerScriptSource is embedded from worker.js at build time.
//go:embed worker.js
var workerScriptSource string
// jsEscape makes a JSON string safe for embedding in a JS single-quoted string.
func jsEscape(s string) string {
	s = strings.ReplaceAll(s, `\`, `\\`)
	s = strings.ReplaceAll(s, `'`, `\'`)
	return s
}

// workerName resolves the worker name from config or default.
func workerName(cfg *config.Config) string {
	if cfg.Cloudflare.WorkerName != "" {
		return cfg.Cloudflare.WorkerName
	}
	return "z-api-proxy"
}

// Deploy pushes the Worker script to Cloudflare via the API.
func Deploy(cfg *config.Config) (*DeployResult, error) {
	if cfg.Cloudflare.AccountID == "" {
		return nil, fmt.Errorf("cloudflare.account_id not set")
	}
	if cfg.Cloudflare.APIToken == "" {
		return nil, fmt.Errorf("cloudflare.api_token not set in secrets.toml")
	}

	name := workerName(cfg)
	script := GenerateScript(cfg)
	client := &http.Client{Timeout: 30 * time.Second}

	// Build multipart form — the key fix: worker.js part needs
	// Content-Type: application/javascript+module for ES module syntax.
	var buf bytes.Buffer
	w := multipart.NewWriter(&buf)

	// Build model mappings as [from, to] pairs for JSON var.
	var fwd, rev [][2]string
	for _, m := range cfg.Models {
		fwd = append(fwd, [2]string{m.From, m.To})
		rev = append(rev, [2]string{m.To, m.From})
	}
	fwdJSON, _ := json.Marshal(fwd)
	revJSON, _ := json.Marshal(rev)

	metadata := map[string]interface{}{
		"main_module":        "worker.js",
		"compatibility_date": "2024-09-23",
		"bindings": []map[string]interface{}{
			{
				"type":          "plain_text",
				"name":          "UPSTREAM",
				"text":          strings.TrimSuffix(cfg.Upstream.BaseURL, "/"),
			},
			{
				"type":          "plain_text",
				"name":          "MODEL_MAPPINGS",
				"text":          string(fwdJSON),
			},
			{
				"type":          "plain_text",
				"name":          "MODEL_REVERSE",
				"text":          string(revJSON),
			},
		},
	}
	if cfg.Cloudflare.EnableLogging {
		metadata["observability"] = map[string]bool{
			"enabled": true,
		}
	}
	metaJSON, _ := json.Marshal(metadata)
	_ = w.WriteField("metadata", string(metaJSON))

	// Create the file part with explicit content type.
	h := make(map[string][]string)
	h["Content-Disposition"] = []string{fmt.Sprintf(`form-data; name="worker.js"; filename="worker.js"`)}
	h["Content-Type"] = []string{"application/javascript+module"}
	filePart, err := w.CreatePart(textproto.MIMEHeader(h))
	if err != nil {
		w.Close()
		return nil, fmt.Errorf("cannot create form part: %w", err)
	}
	filePart.Write([]byte(script))
	w.Close()

	// Upload the script.
	url := fmt.Sprintf("%s/accounts/%s/workers/scripts/%s", apiBaseOverride, cfg.Cloudflare.AccountID, name)
	req, err := http.NewRequest("PUT", url, &buf)
	if err != nil {
		return nil, fmt.Errorf("cannot create request: %w", err)
	}
	req.Header.Set("Authorization", "Bearer "+cfg.Cloudflare.APIToken)
	req.Header.Set("Content-Type", w.FormDataContentType())

	resp, err := client.Do(req)
	if err != nil {
		return nil, fmt.Errorf("deploy request failed: %w", err)
	}
	respBody, _ := io.ReadAll(resp.Body)
	resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		var cfErr cfResponse
		json.Unmarshal(respBody, &cfErr)
		return nil, fmt.Errorf("Cloudflare rejected deploy (HTTP %d): %s\n\nFull response:\n%s",
			resp.StatusCode, cfErr.ErrorString(), truncate(string(respBody), 500))
	}

	log.Printf("worker: script uploaded successfully")

	// Set API key (real upstream key forwarded to z.ai).
	if cfg.Upstream.APIKey != "" {
		if err := setSecret(client, cfg, name, "API_KEY", cfg.Upstream.APIKey); err != nil {
			log.Printf("worker: warning — failed to set API_KEY secret: %v", err)
		} else {
			log.Printf("worker: API_KEY secret set")
		}
	}

	// Set cursor proxy key (what Cursor sends — swapped for real key on upstream).
	if cfg.Proxy.CursorKey != "" {
		if err := setSecret(client, cfg, name, "CURSOR_KEY", cfg.Proxy.CursorKey); err != nil {
			log.Printf("worker: warning — failed to set CURSOR_KEY secret: %v", err)
		} else {
			log.Printf("worker: CURSOR_KEY secret set")
		}
	}

	// Enable workers.dev subdomain.
	subdomainURL := fmt.Sprintf("%s/accounts/%s/workers/scripts/%s/subdomain",
		apiBaseOverride, cfg.Cloudflare.AccountID, name)
	enableJSON, _ := json.Marshal(map[string]bool{"enabled": true})
	enableReq, _ := http.NewRequest("POST", subdomainURL, bytes.NewReader(enableJSON))
	enableReq.Header.Set("Authorization", "Bearer "+cfg.Cloudflare.APIToken)
	enableReq.Header.Set("Content-Type", "application/json")
	enableResp, err := client.Do(enableReq)
	if err == nil {
		enableResp.Body.Close()
	}

	// Get subdomain for URL construction.
	workerURL, err := getWorkerURL(client, cfg, name)
	if err != nil {
		workerURL = fmt.Sprintf("https://%s.workers.dev", name)
	}

	// Attach custom domain if configured.
	finalURL := workerURL
	if cfg.Cloudflare.WorkerHostname != "" {
		hostname := strings.TrimPrefix(strings.TrimPrefix(cfg.Cloudflare.WorkerHostname, "https://"), "http://")
		customURL, err := attachCustomDomain(client, cfg, name, hostname)
		if err != nil {
			log.Printf("worker: warning — custom domain setup failed: %v", err)
		} else {
			finalURL = customURL
			log.Printf("worker: custom domain attached — %s", customURL)
		}
	}

	return &DeployResult{
		URL:       finalURL,
		Script:    script,
		AccountID: cfg.Cloudflare.AccountID,
	}, nil
}

// attachCustomDomain links a custom hostname (e.g. proxy.yourdomain.com)
// to the Worker via the Cloudflare Workers Custom Domains API.
// This automatically creates the required DNS record and route.
func attachCustomDomain(client *http.Client, cfg *config.Config, workerName, hostname string) (string, error) {
	// Extract domain from hostname for zone lookup.
	parts := strings.SplitN(hostname, ".", 2)
	if len(parts) < 2 {
		return "", fmt.Errorf("invalid hostname %q", hostname)
	}
	domain := parts[1]

	// Find zone ID.
	zoneURL := fmt.Sprintf("%s/zones?name=%s", apiBaseOverride, domain)
	zoneReq, _ := http.NewRequest("GET", zoneURL, nil)
	zoneReq.Header.Set("Authorization", "Bearer "+cfg.Cloudflare.APIToken)
	zoneResp, err := client.Do(zoneReq)
	if err != nil {
		return "", fmt.Errorf("zone lookup failed: %w", err)
	}
	zoneBody, _ := io.ReadAll(zoneResp.Body)
	zoneResp.Body.Close()

	var zoneResult struct {
		Result []struct {
			ID string `json:"id"`
		} `json:"result"`
	}
	if json.Unmarshal(zoneBody, &zoneResult) != nil || len(zoneResult.Result) == 0 {
		return "", fmt.Errorf("zone not found for domain %q — add it to Cloudflare first", domain)
	}
	zoneID := zoneResult.Result[0].ID

	// Attach custom domain via Workers Domains API.
	domainsURL := fmt.Sprintf("%s/accounts/%s/workers/domains", apiBaseOverride, cfg.Cloudflare.AccountID)
	domainsBody := map[string]string{
		"environment": "production",
		"hostname":    hostname,
		"service":     workerName,
		"zone_id":     zoneID,
	}
	domainsJSON, _ := json.Marshal(domainsBody)
	domainsReq, _ := http.NewRequest("PUT", domainsURL, bytes.NewReader(domainsJSON))
	domainsReq.Header.Set("Authorization", "Bearer "+cfg.Cloudflare.APIToken)
	domainsReq.Header.Set("Content-Type", "application/json")

	domainsResp, err := client.Do(domainsReq)
	if err != nil {
		return "", fmt.Errorf("custom domain API call failed: %w", err)
	}
	domainsRespBody, _ := io.ReadAll(domainsResp.Body)
	domainsResp.Body.Close()

	if domainsResp.StatusCode != http.StatusOK && domainsResp.StatusCode != 201 {
		var cfErr cfResponse
		json.Unmarshal(domainsRespBody, &cfErr)
		return "", fmt.Errorf("custom domain API returned HTTP %d: %s",
			domainsResp.StatusCode, cfErr.ErrorString())
	}

	return "https://" + hostname, nil
}

// setSecret sets a Cloudflare Worker secret via the API.
func setSecret(client *http.Client, cfg *config.Config, workerName, secretName, secretValue string) error {
	url := fmt.Sprintf("%s/accounts/%s/workers/scripts/%s/secrets",
		apiBaseOverride, cfg.Cloudflare.AccountID, workerName)
	body := map[string]string{
		"name": secretName,
		"text": secretValue,
		"type": "secret_text",
	}
	bodyJSON, _ := json.Marshal(body)
	req, err := http.NewRequest("PUT", url, bytes.NewReader(bodyJSON))
	if err != nil {
		return err
	}
	req.Header.Set("Authorization", "Bearer "+cfg.Cloudflare.APIToken)
	req.Header.Set("Content-Type", "application/json")
	resp, err := client.Do(req)
	if err != nil {
		return err
	}
	defer resp.Body.Close()
	respBody, _ := io.ReadAll(resp.Body)
	if resp.StatusCode != http.StatusOK {
		var cfErr cfResponse
		json.Unmarshal(respBody, &cfErr)
		return fmt.Errorf("secret API returned HTTP %d: %s", resp.StatusCode, cfErr.ErrorString())
	}
	return nil
}

// getWorkerURL retrieves the workers.dev URL for the script.
func getWorkerURL(client *http.Client, cfg *config.Config, name string) (string, error) {
	subURL := fmt.Sprintf("%s/accounts/%s/workers/subdomain", apiBaseOverride, cfg.Cloudflare.AccountID)
	req, _ := http.NewRequest("GET", subURL, nil)
	req.Header.Set("Authorization", "Bearer "+cfg.Cloudflare.APIToken)
	resp, err := client.Do(req)
	if err != nil {
		return "", err
	}
	defer resp.Body.Close()
	body, _ := io.ReadAll(resp.Body)
	var result struct {
		Result struct {
			Subdomain string `json:"subdomain"`
		} `json:"result"`
	}
	if json.Unmarshal(body, &result) == nil && result.Result.Subdomain != "" {
		return fmt.Sprintf("https://%s.%s.workers.dev", name, result.Result.Subdomain), nil
	}
	return "", fmt.Errorf("could not determine workers.dev subdomain")
}

// Delete removes the Worker script from Cloudflare.
func Delete(cfg *config.Config) error {
	if cfg.Cloudflare.AccountID == "" || cfg.Cloudflare.APIToken == "" {
		return fmt.Errorf("cloudflare credentials not configured")
	}
	name := workerName(cfg)
	url := fmt.Sprintf("%s/accounts/%s/workers/scripts/%s", apiBaseOverride, cfg.Cloudflare.AccountID, name)
	client := &http.Client{Timeout: 30 * time.Second}
	req, _ := http.NewRequest("DELETE", url, nil)
	req.Header.Set("Authorization", "Bearer "+cfg.Cloudflare.APIToken)
	resp, err := client.Do(req)
	if err != nil {
		return fmt.Errorf("delete request failed: %w", err)
	}
	defer resp.Body.Close()
	body, _ := io.ReadAll(resp.Body)
	if resp.StatusCode != http.StatusOK {
		var cfErr cfResponse
		json.Unmarshal(body, &cfErr)
		return fmt.Errorf("delete returned HTTP %d: %s", resp.StatusCode, cfErr.ErrorString())
	}
	log.Printf("worker: deleted %s", name)
	return nil
}

// HealthCheck sends a GET request to the Worker's /health endpoint.
// Returns nil if the Worker responds with 200.
func HealthCheck(workerURL, apiKey string) error {
	client := &http.Client{Timeout: 15 * time.Second}
	req, err := http.NewRequest("GET", workerURL+"/health", nil)
	if err != nil {
		return fmt.Errorf("cannot create request: %w", err)
	}
	if apiKey != "" {
		req.Header.Set("Authorization", "Bearer "+apiKey)
	}
	resp, err := client.Do(req)
	if err != nil {
		return fmt.Errorf("worker unreachable: %w", err)
	}
	defer resp.Body.Close()
	if resp.StatusCode != http.StatusOK {
		return fmt.Errorf("worker returned HTTP %d", resp.StatusCode)
	}
	return nil
}

// TestChat sends a minimal "1+1=?" chat completion request through the
// Worker to verify end-to-end functionality: key validation, model
// rewriting, upstream forwarding, and response handling.
// Returns the response body or an error with full details.
func TestChat(workerURL, apiKey string) (string, error) {
	body := map[string]interface{}{
		"model":    "z.ai/glm-5.2",
		"messages": []map[string]string{{"role": "user", "content": "1+1=?"}},
	}
	bodyJSON, _ := json.Marshal(body)

	client := &http.Client{Timeout: 30 * time.Second}
	req, err := http.NewRequest("POST", workerURL+"/v1/chat/completions", bytes.NewReader(bodyJSON))
	if err != nil {
		return "", fmt.Errorf("cannot create request: %w", err)
	}
	req.Header.Set("Content-Type", "application/json")
	req.Header.Set("Authorization", "Bearer "+apiKey)

	resp, err := client.Do(req)
	if err != nil {
		return "", fmt.Errorf("worker unreachable: %w", err)
	}
	defer resp.Body.Close()
	respBody, _ := io.ReadAll(resp.Body)

	if resp.StatusCode != http.StatusOK {
		return string(respBody), fmt.Errorf("HTTP %d: %s", resp.StatusCode, truncate(string(respBody), 300))
	}

	return string(respBody), nil
}

// GetDeployedURL retrieves the current workers.dev URL.
func GetDeployedURL(cfg *config.Config) (string, error) {
	client := &http.Client{Timeout: 15 * time.Second}
	return getWorkerURL(client, cfg, workerName(cfg))
}

// truncate limits a string to maxLen characters with ellipsis.
func truncate(s string, maxLen int) string {
	if len(s) <= maxLen {
		return s
	}
	return s[:maxLen] + "..."
}
